LED_SKETCH_TEMPLATE = """
/**
 * LED Control Sketch - {description}
 * Generated by Arduino Vibe IDE
 */

#include <FastLED.h>

// LED Configuration
#define LED_PIN        {led_pin}
#define NUM_LEDS       {num_leds}
#define LED_TYPE       {led_type}
#define COLOR_ORDER    {color_order}
#define BRIGHTNESS     {brightness}

CRGB leds[NUM_LEDS];

// Runtime command parser
#define CMD_BUFFER_SIZE 64
char cmd_buffer[CMD_BUFFER_SIZE];
int cmd_idx = 0;

// LED Effects
enum Effect {{
    EFFECT_SOLID,
    EFFECT_RAINBOW,
    EFFECT_PULSE,
    EFFECT_FIRE,
    EFFECT_WAVE,
    EFFECT_RUNNING,
    EFFECT_RANDOM,
    EFFECT_CHASE,
}};

Effect current_effect = EFFECT_SOLID;
CRGB current_color = CRGB::White;
uint8_t current_brightness = {brightness};
uint32_t last_update = 0;
uint8_t speed = 10;

void setup() {{
    Serial.begin(115200);
    while (!Serial) {{ }}  // Wait for serial (USB boards)

    LED.addLeds<LED_TYPE, LED_PIN, COLOR_ORDER>(leds, NUM_LEDS);
    LED.setBrightness(current_brightness);
    fill_solid(leds, NUM_LEDS, current_color);
    LED.show();

    Serial.println("LEDS_READY");
    Serial.print("LEDS_NUM=");
    Serial.println(NUM_LEDS);
}}

void loop() {{
    parse_serial_command();
    update_effect();
    LED.show();
}}

void parse_serial_command() {{
    while (Serial.available()) {{
        char c = Serial.read();
        if (c == '\\\\n') {{
            cmd_buffer[cmd_idx] = '\\\\0';
            process_command(cmd_buffer);
            cmd_idx = 0;
        }} else if (cmd_idx < CMD_BUFFER_SIZE - 1) {{
            cmd_buffer[cmd_idx++] = c;
        }}
    }}
}}

void process_command(char* cmd) {{
    // LED control: LED <index> <R> <G> <B>
    if (strncmp(cmd, "LED", 3) == 0) {{
        int idx, r, g, b;
        if (sscanf(cmd + 4, "%d %d %d %d", &idx, &r, &g, &b) == 4) {{
            if (idx >= 0 && idx < NUM_LEDS) {{
                leds[idx].setRGB(r, g, b);
                Serial.print("LED_");
                Serial.print(idx);
                Serial.println(" OK");
            }}
        }}
        return;
    }}

    // All LEDs: ALL <R> <G> <B>
    if (strncmp(cmd, "ALL", 3) == 0) {{
        int r, g, b;
        if (sscanf(cmd + 4, "%d %d %d", &r, &g, &b) == 3) {{
            fill_solid(leds, NUM_LEDS, CRGB(r, g, b));
            Serial.println("ALL OK");
        }}
        return;
    }}

    // Brightness: BRIGHT <0-255>
    if (strncmp(cmd, "BRIGHT", 6) == 0) {{
        int b;
        if (sscanf(cmd + 7, "%d", &b) == 1) {{
            current_brightness = constrain(b, 0, 255);
            LED.setBrightness(current_brightness);
            Serial.print("BRIGHT ");
            Serial.println(current_brightness);
        }}
        return;
    }}

    // Effect: EFFECT <name>
    if (strncmp(cmd, "EFFECT", 6) == 0) {{
        char effect_name[16];
        if (sscanf(cmd + 7, "%15s", effect_name) == 1) {{
            set_effect(effect_name);
            Serial.print("EFFECT ");
            Serial.println(effect_name);
        }}
        return;
    }}

    // Speed: SPEED <0-255>
    if (strncmp(cmd, "SPEED", 5) == 0) {{
        int s;
        if (sscanf(cmd + 6, "%d", &s) == 1) {{
            speed = constrain(s, 1, 255);
            Serial.print("SPEED ");
            Serial.println(speed);
        }}
        return;
    }}

    // Color: COLOR <R> <G> <B>
    if (strncmp(cmd, "COLOR", 5) == 0) {{
        int r, g, b;
        if (sscanf(cmd + 6, "%d %d %d", &r, &g, &b) == 3) {{
            current_color = CRGB(r, g, b);
            Serial.print("COLOR ");
            Serial.print(r);
            Serial.print(",");
            Serial.print(g);
            Serial.print(",");
            Serial.println(b);
        }}
        return;
    }}

    Serial.println("CMD_OK");
}}

void set_effect(char* name) {{
    if (strcmp(name, "solid") == 0)      current_effect = EFFECT_SOLID;
    else if (strcmp(name, "rainbow") == 0) current_effect = EFFECT_RAINBOW;
    else if (strcmp(name, "pulse") == 0)  current_effect = EFFECT_PULSE;
    else if (strcmp(name, "fire") == 0)   current_effect = EFFECT_FIRE;
    else if (strcmp(name, "wave") == 0)   current_effect = EFFECT_WAVE;
    else if (strcmp(name, "running") == 0) current_effect = EFFECT_RUNNING;
    else if (strcmp(name, "random") == 0) current_effect = EFFECT_RANDOM;
    else if (strcmp(name, "chase") == 0)  current_effect = EFFECT_CHASE;
}}

void update_effect() {{
    uint32_t now = millis();
    if (now - last_update < (256 - speed)) return;
    last_update = now;

    switch (current_effect) {{
        case EFFECT_SOLID:
            fill_solid(leds, NUM_LEDS, current_color);
            break;

        case EFFECT_RAINBOW: {{
            uint8_t increment = speed;
            for (int i = 0; i < NUM_LEDS; i++) {{
                leds[i] = CHSV((i * 256 / NUM_LEDS + increment) % 256, 255, current_brightness);
            }}
            break;
        }}

        case EFFECT_PULSE: {{
            uint8_t wave = sin8(now / (32 / speed));
            fill_solid(leds, NUM_LEDS, current_color);
            for (int i = 0; i < NUM_LEDS; i++) {{
                leds[i].nscale8(wave);
            }}
            break;
        }}

        case EFFECT_WAVE: {{
            for (int i = 0; i < NUM_LEDS; i++) {{
                uint8_t wave = sin8((i * 8 + now / (16 / speed)) & 0xFF);
                leds[i] = CHSV(wave, 255, current_brightness);
            }}
            break;
        }}

        case EFFECT_RUNNING: {{
            fill_solid(leds, NUM_LEDS, CRGB::Black);
            int pos = (now / (32 / speed)) % NUM_LEDS;
            leds[pos] = current_color;
            break;
        }}

        case EFFECT_CHASE: {{
            fill_solid(leds, NUM_LEDS, CRGB::Black);
            int step = NUM_LEDS / 5;
            int offset = (now / (32 / speed)) % step;
            for (int i = 0; i < 5; i++) {{
                int pos = (offset + i * step) % NUM_LEDS;
                leds[pos] = current_color;
            }}
            break;
        }}

        case EFFECT_RANDOM: {{
            for (int i = 0; i < NUM_LEDS / 10; i++) {{
                int pos = random(NUM_LEDS);
                leds[pos] = CHSV(random(256), 200, current_brightness);
            }}
            break;
        }}

        case EFFECT_FIRE:
            // Simplified fire effect
            for (int i = 0; i < NUM_LEDS; i++) {{
                uint8_t heat = random(256);
                leds[i] = HeatColor(heat);
            }}
            break;
    }}
}}
"""


IR_REMOTE_TEMPLATE = """
/**
 * IR Remote Control Sketch
 * Generated by Arduino Vibe IDE
 */

#include <IRremote.h>

#define RECV_PIN {ir_pin}

IRrecv irrecv(RECV_PIN);
decode_results results;

// IR command buffer for serial communication
#define CMD_BUFFER_SIZE 64
char cmd_buffer[CMD_BUFFER_SIZE];
int cmd_idx = 0;

// Stored IR codes for replay
#define MAX_CODES 32
struct IRCode {{
    char name[32];
    uint64_t code;
    uint8_t protocol;
}} ir_codes[MAX_CODES];
int ir_code_count = 0;

void setup() {{
    Serial.begin(115200);
    while (!Serial) {{ }}

    irrecv.enableIRIn();
    Serial.println("IR_READY");
    Serial.println("IR receiver initialized");
}}

void loop() {{
    parse_serial_command();

    if (irrecv.decode(&results)) {{
        char msg[128];
        snprintf(msg, sizeof(msg), "IR_RECV:%s:0x%08lX",
                 protocol_name(results.value), results.value);
        Serial.println(msg);
        irrecv.resume();
    }}
}}

void parse_serial_command() {{
    while (Serial.available()) {{
        char c = Serial.read();
        if (c == '\\\\n') {{
            cmd_buffer[cmd_idx] = '\\\\0';
            process_command(cmd_buffer);
            cmd_idx = 0;
        }} else if (cmd_idx < CMD_BUFFER_SIZE - 1) {{
            cmd_buffer[cmd_idx++] = c;
        }}
    }}
}}

void process_command(char* cmd) {{
    // Send IR code: IR_SEND <name>
    if (strncmp(cmd, "IR_SEND", 7) == 0) {{
        char name[32];
        if (sscanf(cmd + 8, "%31s", name) == 1) {{
            send_ir_by_name(name);
        }}
        return;
    }}

    // Send raw code: IR_RAW <hex_code>
    if (strncmp(cmd, "IR_RAW", 6) == 0) {{
        unsigned long code;
        if (sscanf(cmd + 7, "%08lx", &code) == 1) {{
            irsend.sendNEC(code, 32);
            Serial.print("IR_RAW ");
            Serial.println(code);
        }}
        return;
    }}

    // Save code: IR_SAVE <name> <hex_code>
    if (strncmp(cmd, "IR_SAVE", 7) == 0) {{
        char name[32];
        unsigned long code;
        if (sscanf(cmd + 8, "%31s %08lx", name, &code) == 2) {{
            save_ir_code(name, code);
        }}
        return;
    }}

    // List codes
    if (strcmp(cmd, "IR_LIST") == 0) {{
        Serial.println("IR_CODES:");
        for (int i = 0; i < ir_code_count; i++) {{
            Serial.print("  ");
            Serial.print(ir_codes[i].name);
            Serial.print(":0x");
            Serial.println(ir_codes[i].code, HEX);
        }}
    }}

    Serial.println("CMD_OK");
}}

void send_ir_by_name(char* name) {{
    for (int i = 0; i < ir_code_count; i++) {{
        if (strcmp(ir_codes[i].name, name) == 0) {{
            irsend.sendNEC(ir_codes[i].code, 32);
            Serial.print("IR_SEND ");
            Serial.println(name);
            return;
        }}
    }}
    Serial.print("IR_NOT_FOUND:");
    Serial.println(name);
}}

void save_ir_code(char* name, uint64_t code) {{
    if (ir_code_count < MAX_CODES) {{
        strncpy(ir_codes[ir_code_count].name, name, 31);
        ir_codes[ir_code_count].code = code;
        ir_codes[ir_code_count].protocol = NEC;
        ir_code_count++;
        Serial.print("IR_SAVED:");
        Serial.println(name);
    }}
}}

const char* protocol_name(unsigned long code) {{
    // Simplified protocol detection
    return "NEC";
}}
"""


