SYSTEM_PROMPT = """
You are an expert Arduino C++ firmware engineer. Generate clean, well-structured
Arduino sketches based on natural language descriptions.

Requirements:
- Use modern C++ practices within Arduino constraints
- Include error handling where practical
- Add serial command parsing for runtime control
- Comment all major sections
- Use #define for pin mappings (easy to reconfigure)
- Return ONLY the .ino code, no markdown fences or explanations

Board context: {board}
Hardware context: {hardware_context}
"""


def build_led_prompt(
    description: str = "LED control",
    led_pin: int = 6,
    num_leds: int = 288,
    led_type: str = "SK6812",
    color_order: str = "GRBW",
    brightness: int = 128,
    board: str = "arduino:avr:nano",
) -> tuple[str, str]:
    """Build LED sketch generation prompt."""
    system = SYSTEM_PROMPT.format(
        board=board,
        hardware_context=(
            f"FastLED with {led_type} LEDs, {num_leds} count, "
            f"data pin {led_pin}, color order {color_order}"
        ),
    )

    user = f"""
Generate an Arduino sketch for: {description}

Hardware:
- Board: {board}
- LEDs: {led_type} ({num_leds} LEDs)
- Data Pin: D{led_pin}
- Color Order: {color_order}
- Default Brightness: {brightness}

Features:
- FastLED library integration
- Serial command interface for runtime control
  - LED <index> <R> <G> <B> - Set individual LED
  - ALL <R> <G> <B> - Set all LEDs
  - BRIGHT <0-255> - Set brightness
  - EFFECT <name> - Set animation effect
  - SPEED <0-255> - Set animation speed
  - COLOR <R> <G> <B> - Set base color for effects
- Animation effects: solid, rainbow, pulse, fire, wave, running, chase, random
- Non-blocking timing with millis()
"""

    return system, user


def build_ir_prompt(
    ir_pin: int = 2,
    board: str = "arduino:avr:nano",
) -> tuple[str, str]:
    """Build IR remote sketch prompt."""
    system = SYSTEM_PROMPT.format(
        board=board,
        hardware_context=(
            f"IR receiver on pin D{ir_pin}, IRremote library"
        ),
    )

    user = f"""
Generate an Arduino sketch for IR remote control and relay.

Hardware:
- Board: {board}
- IR Receiver Pin: D{ir_pin}
- Library: IRremote

Features:
- Receive IR signals and decode
- Serial command interface:
  - IR_SEND <name> - Send stored IR code
  - IR_RAW <hex_code> - Send raw NEC code
  - IR_SAVE <name> <hex_code> - Store IR code
  - IR_LIST - List stored codes
- Report received IR codes over serial
"""

    return system, user


def build_sensor_prompt(
    sensors: list[str] = None,
    board: str = "arduino:avr:nano",
) -> tuple[str, str]:
    """Build sensor reading sketch prompt."""
    sensor_list = sensors or ["DHT22 temperature/humidity"]

    system = SYSTEM_PROMPT.format(
        board=board,
        hardware_context=(
            f"Sensors: {', '.join(sensor_list)}"
        ),
    )

    user = f"""
Generate an Arduino sketch for reading sensor data.

Hardware:
- Board: {board}
- Sensors: {', '.join(sensor_list)}

Features:
- Read sensor values at regular intervals
- Serial output with structured format: SENSOR <type>:<value>
- Serial command interface:
  - SENSOR_READ or READ - Trigger immediate reading
  - INTERVAL <ms> - Set reading interval
"""

    return system, user


def build_servo_prompt(
    servos: list[dict] = None,
    board: str = "arduino:avr:nano",
) -> tuple[str, str]:
    """Build servo control sketch prompt."""
    default_servos = [{"pin": 9, "name": "servo1"}, {"pin": 10, "name": "servo2"}]
    servo_list = servos or default_servos

    pins_str = ", ".join(
        f"{s.get('name', 'servo')} on D{s.get('pin', '?')}" for s in servo_list
    )

    system = SYSTEM_PROMPT.format(
        board=board,
        hardware_context=f"Servos: {pins_str}",
    )

    user = f"""
Generate an Arduino sketch for servo motor control.

Hardware:
- Board: {board}
- Servos: {pins_str}

Features:
- Servo library integration
- Serial command interface:
  - SERVO <index> <angle> - Move servo to angle (0-180)
  - SERVO_HOME - Move all servos to center position
- Non-blocking control
"""

    return system, user


def build_generic_prompt(
    description: str,
    hardware: str = "",
    board: str = "arduino:avr:nano",
    features: str = "",
) -> tuple[str, str]:
    """Build generic sketch generation prompt."""
    system = SYSTEM_PROMPT.format(
        board=board,
        hardware_context=hardware or "Standard Arduino board",
    )

    user = f"""
Generate an Arduino sketch: {description}

Hardware:
- Board: {board}
- Configuration: {hardware}

Features:
{features}

Requirements:
- Include serial command parsing for runtime control
- Use non-blocking timing (millis())
- Well-commented code
- #define for pin mappings
- Return READY status on startup
"""

    return system, user


def build_bt_bridge_prompt(
    bt_rx: int = 11,
    bt_tx: int = 10,
    baudrate: int = 9600,
    board: str = "arduino:avr:nano",
) -> tuple[str, str]:
    """Build Bluetooth bridge sketch prompt."""
    system = SYSTEM_PROMPT.format(
        board=board,
        hardware_context=(
            f"HC-05 Bluetooth module, RXD->D{bt_rx}, TXD->D{bt_tx}, "
            f"baudrate {baudrate}, SoftwareSerial"
        ),
    )

    user = f"""
Generate an Arduino sketch for HC-05 Bluetooth serial bridge.

Hardware:
- Board: {board}
- HC-05 RXD -> D{bt_rx}
- HC-05 TXD -> D{bt_tx}
- Baudrate: {baudrate}
- Library: SoftwareSerial

Features:
- Full-duplex serial bridge between hardware Serial and Bluetooth
- Transparent data forwarding both directions
- Ready status reporting
"""

    return system, user


def generate_sketch_from_prompt(
    prompt: str,
    board: str = "arduino:avr:nano",
    hardware_context: dict = None,
) -> str:
    """
    Generate an Arduino sketch from a natural language prompt.
    Uses template-based generation (AI integration point).

    Args:
        prompt: Natural language description
        board: Target board FQBN
        hardware_context: Dict with hardware configuration

    Returns:
        Generated .ino sketch code
    """
    ctx = hardware_context or {}
    prompt_lower = prompt.lower()

    # Determine sketch type from prompt
    if any(kw in prompt_lower for kw in ["led", "neopixel", "ws2812", "sk6812", "fastled", "rgb"]):
        return LED_SKETCH_TEMPLATE.format(
            description=prompt,
            led_pin=ctx.get("led_pin", 6),
            num_leds=ctx.get("num_leds", 288),
            led_type=ctx.get("led_type", "SK6812"),
            color_order=ctx.get("color_order", "GRBW"),
            brightness=ctx.get("brightness", 128),
        )

    if any(kw in prompt_lower for kw in ["ir", "remote", "infrared", "irremote"]):
        return IR_REMOTE_TEMPLATE.format(ir_pin=ctx.get("ir_pin", 2))

    if any(kw in prompt_lower for kw in ["sensor", "dht", "bmp", "bme", "temperature", "humidity", "pressure"]):
        sensor_desc = prompt
        includes = "#include <DHT.h>\n#include <DHT_U.h>"
        pin_defs = "#define DHT_PIN 4\n#define DHT_TYPE DHT22"
        setup_code = "DHT dht(DHT_PIN, DHT_TYPE);\ndht.begin();"
        read_code = """
    float temp = dht.readTemperature();
    float hum = dht.readHumidity();
    if (!isnan(temp) && !isnan(hum)) {
        Serial.print("SENSOR_TEMP:");
        Serial.println(temp, 2);
        Serial.print("SENSOR_HUM:");
        Serial.println(hum, 2);
    }
"""
        return SENSOR_TEMPLATE.format(
            description=sensor_desc,
            includes=includes,
            pin_defs=pin_defs,
            setup_code=setup_code,
            sensor_read_code=read_code,
        )

    if any(kw in prompt_lower for kw in ["servo", "motor", "rotate"]):
        servo_count = ctx.get("servo_count", 1)
        servo_defs = "#include <Servo.h>\nServo servo1;"
        servo_setup = "servo1.attach(" + str(ctx.get("servo_pin", 9)) + ");"
        servo_move = "    if (idx == 0) servo1.write(angle);"
        return SERVO_TEMPLATE.format(
            servo_defs=servo_defs,
            servo_setup=servo_setup,
            servo_count=servo_count,
            servo_move_code=servo_move,
        )

    if any(kw in prompt_lower for kw in ["bluetooth", "bt", "hc-05", "hc05", "rfcomm"]):
        return BT_BRIDGE_TEMPLATE

    # Generic template
    return GENERIC_TEMPLATE.format(
        description=prompt,
        includes="// Add library includes here",
        pin_defs="// Define pins here",
        setup_code="// Initialize hardware here",
        main_loop="// Main loop logic here\ndelay(100);",
        command_handlers="// Add command handlers here",
    )


